def update_option_instrument_key(data_dict):
    ltp_bank = data_dict['feeds']['NSE_INDEX|Nifty Bank']['ff']['indexFF']['ltpc']['ltp']
    ltp_nifty = data_dict['feeds']["NSE_INDEX|Nifty 50"]['ff']['indexFF']['ltpc']['ltp']
    bank_options = instrument.categorize_options("BANKNIFTY", ltp_bank)
    nifty_options = instrument.categorize_options("NIFTY", ltp_nifty)

    bank_options = bank_options[0] + bank_options[1]
    nifty_options = nifty_options[0] + nifty_options[1]
    all_options = bank_options + nifty_options

    # Prepare instrument keys for fetching real-time LTP data
    instrument_keys = ','.join([option['instrument_key'] for option in all_options])
    with open ("instrument_key.txt",'w') as k:
        k.write(instrument_keys)



def make_options_data(data_dict, csv_filename='options_data.csv'):
    try:
        update_option_instrument_key(data_dict=data_dict)
        # Load data from JSON file
        with open(json_filename, 'r') as json_file:
            trading_symbols = json.load(json_file)

        # Read existing data
        existing_data = {}
        file_exists = os.path.isfile(csv_filename) and os.path.getsize(csv_filename) > 0
        if file_exists:
            with open(csv_filename, 'r', newline='') as csvfile:
                reader = csv.DictReader(csvfile)
                for row in reader:
                    existing_data[row['Instrument Token']] = row

        # Update or add new data
        timestamp = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        for instrument_key, instrument_data in data_dict['feeds'].items():
            # Check for option data
            if 'marketFF' in instrument_data['ff'] and 'optionGreeks' in instrument_data['ff']['marketFF']:
                ltp = instrument_data['ff']['marketFF']['ltpc']['ltp']
                tradingsymbol = trading_symbols[instrument_key]
                option_type = 'CE' if 'CE' in tradingsymbol else 'PE'
                new_row = {
                    'Timestamp': timestamp,
                    'Instrument': tradingsymbol,
                    'LTP': ltp,
                    'Instrument Token': instrument_key,
                    'Quantity': 1,
                    'Transaction Type': 'BUY',
                    'Order Type': 'MARKET',
                    'Option Type': option_type,
                    'Product': 'I',
                    'Price': ltp,
                    'Trigger Price': 0,
                    'Is AMO': False
                }

                # Update existing data or add new
                existing_data[instrument_key] = new_row

        # Write updated data back to the CSV file
        with open(csv_filename, 'w', newline='') as csvfile:
            fieldnames = ['Timestamp', 'Instrument', 'LTP', 'Instrument Token', 'Quantity', 'Transaction Type', 'Order Type', 'Option Type', 'Product', 'Price', 'Trigger Price', 'Is AMO']
            csv_writer = csv.DictWriter(csvfile, fieldnames=fieldnames)
            csv_writer.writeheader()
            for row in existing_data.values():
                csv_writer.writerow(row)

    except KeyError as e:
        # print(f"KeyError: {e}")
        return None






